# Middleware

Middleware runs before every matched request in Next.js, enabling authentication, redirects, rewrites, and header manipulation at the edge.

## Setup

Create `middleware.ts` at the root of your project (next to `app/` or `pages/`) or inside `src/`.

```tsx
// middleware.ts
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  // Runs on every matched request
  return NextResponse.next()
}

// Optionally scope to specific paths
export const config = {
  matcher: ['/dashboard/:path*', '/api/:path*'],
}
```

## Authentication Guard

```tsx
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  const token = request.cookies.get('session')?.value

  // Protect dashboard routes
  if (request.nextUrl.pathname.startsWith('/dashboard')) {
    if (!token) {
      const loginUrl = new URL('/login', request.url)
      loginUrl.searchParams.set('callbackUrl', request.nextUrl.pathname)
      return NextResponse.redirect(loginUrl)
    }
  }

  return NextResponse.next()
}

export const config = {
  matcher: ['/dashboard/:path*', '/settings/:path*'],
}
```

## Redirects

```tsx
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Permanent redirect
  if (pathname === '/old-page') {
    return NextResponse.redirect(new URL('/new-page', request.url), 308)
  }

  // Temporary redirect
  if (pathname === '/maintenance') {
    return NextResponse.redirect(new URL('/coming-soon', request.url))
  }

  return NextResponse.next()
}
```

## Rewrites (URL Masking)

```tsx
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Proxy API requests to external service (URL stays the same for the user)
  if (pathname.startsWith('/api/external')) {
    return NextResponse.rewrite(
      new URL(pathname.replace('/api/external', ''), 'https://api.example.com')
    )
  }

  return NextResponse.next()
}
```

## Setting Headers

```tsx
export function middleware(request: NextRequest) {
  // Add request headers (visible to server components and route handlers)
  const requestHeaders = new Headers(request.headers)
  requestHeaders.set('x-request-id', crypto.randomUUID())

  const response = NextResponse.next({
    request: { headers: requestHeaders },
  })

  // Add response headers
  response.headers.set('X-Frame-Options', 'DENY')
  response.headers.set('X-Content-Type-Options', 'nosniff')
  response.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin')

  return response
}
```

## Cookies

```tsx
export function middleware(request: NextRequest) {
  const response = NextResponse.next()

  // Read cookies
  const theme = request.cookies.get('theme')?.value

  // Set cookies
  response.cookies.set('visited', 'true', {
    httpOnly: true,
    secure: true,
    sameSite: 'lax',
    maxAge: 60 * 60 * 24 * 30, // 30 days
  })

  // Delete cookies
  response.cookies.delete('old-cookie')

  return response
}
```

## Locale Detection

```tsx
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Skip if locale already in path
  const locales = ['en', 'fr', 'de', 'ja']
  const hasLocale = locales.some(
    locale => pathname.startsWith(`/${locale}/`) || pathname === `/${locale}`
  )
  if (hasLocale) return NextResponse.next()

  // Detect locale from Accept-Language header
  const acceptLang = request.headers.get('Accept-Language') ?? ''
  const detected = locales.find(l => acceptLang.includes(l)) ?? 'en'

  // Rewrite to locale-prefixed path
  return NextResponse.rewrite(
    new URL(`/${detected}${pathname}`, request.url)
  )
}
```

## A/B Testing

```tsx
export function middleware(request: NextRequest) {
  const bucket = request.cookies.get('ab-bucket')?.value
  const response = NextResponse.next()

  if (!bucket) {
    const newBucket = Math.random() < 0.5 ? 'control' : 'variant'
    response.cookies.set('ab-bucket', newBucket)

    if (newBucket === 'variant') {
      return NextResponse.rewrite(
        new URL('/variant' + request.nextUrl.pathname, request.url)
      )
    }
  } else if (bucket === 'variant') {
    return NextResponse.rewrite(
      new URL('/variant' + request.nextUrl.pathname, request.url)
    )
  }

  return response
}
```

## Matcher Configuration

```tsx
export const config = {
  matcher: [
    // Match specific paths
    '/dashboard/:path*',
    '/api/:path*',

    // Match all paths except static files and images
    '/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',
  ],
}
```

Matcher supports:
- `:path` — single segment wildcard
- `:path*` — zero or more segments
- Regex in parentheses `(regex)` for negative lookaheads

## NextRequest API

| Property/Method | Description |
|----------------|-------------|
| `request.nextUrl` | Parsed URL with `pathname`, `searchParams`, `basePath` |
| `request.cookies` | Cookie jar with `get()`, `getAll()`, `set()`, `delete()`, `has()` |
| `request.headers` | Standard Headers object |
| `request.geo` | Geolocation data (`country`, `city`, `region`) — Vercel only |
| `request.ip` | Client IP address — Vercel only |

## NextResponse API

| Method | Description |
|--------|-------------|
| `NextResponse.next()` | Continue to the next middleware or route |
| `NextResponse.redirect(url, status?)` | Redirect to a URL (default 307) |
| `NextResponse.rewrite(url)` | Serve a different URL without changing the browser URL |
| `NextResponse.json(data, init?)` | Return a JSON response |
